// ==== CONFIG: edit these two lines to match your database ====
const MATCH_PROPERTY = 'Name';   // property used to detect duplicates
const KEEP_RULE = 'newest';      // 'newest' | 'oldest' | 'mostFilled'
// ============================================================

const pages = items.map((i) => i.json);

function readValue(page, propName) {
  const props = (page && page.properties) || {};
  const p = props[propName];
  if (!p) return '';
  const t = p.type;
  let v = '';
  if (t === 'title') v = (p.title || []).map((x) => x.plain_text).join('');
  else if (t === 'rich_text') v = (p.rich_text || []).map((x) => x.plain_text).join('');
  else if (t === 'url') v = p.url || '';
  else if (t === 'email') v = p.email || '';
  else if (t === 'phone_number') v = p.phone_number || '';
  else if (t === 'number') v = p.number == null ? '' : String(p.number);
  else if (t === 'select') v = (p.select && p.select.name) || '';
  else if (t === 'status') v = (p.status && p.status.name) || '';
  else if (t === 'formula') v = p.formula ? (p.formula.string ?? p.formula.number ?? '') : '';
  else v = '';
  return String(v).trim().toLowerCase();
}

function filledCount(page) {
  const props = (page && page.properties) || {};
  let n = 0;
  for (const k of Object.keys(props)) {
    if (readValue(page, k) !== '') n += 1;
  }
  return n;
}

function editedTime(page) {
  return page.last_edited_time || page.created_time || '';
}

const groups = {};
let keyless = 0;
for (const page of pages) {
  const key = readValue(page, MATCH_PROPERTY);
  if (!key) { keyless += 1; continue; }
  (groups[key] = groups[key] || []).push(page);
}

const losers = [];
let dupGroups = 0;
for (const key of Object.keys(groups)) {
  const group = groups[key];
  if (group.length < 2) continue;
  dupGroups += 1;
  const sorted = group.slice();
  if (KEEP_RULE === 'mostFilled') {
    sorted.sort((a, b) => filledCount(b) - filledCount(a) || editedTime(b).localeCompare(editedTime(a)));
  } else if (KEEP_RULE === 'oldest') {
    sorted.sort((a, b) => editedTime(a).localeCompare(editedTime(b)));
  } else {
    sorted.sort((a, b) => editedTime(b).localeCompare(editedTime(a)));
  }
  const keeper = sorted[0];
  for (let i = 1; i < sorted.length; i++) {
    const loser = sorted[i];
    losers.push({ json: {
      _type: 'archive',
      pageId: loser.id,
      keyValue: key,
      keptPageId: keeper.id,
      keptUrl: keeper.url || '',
      reason: 'duplicate of kept page ' + keeper.id
    } });
  }
}

const recap = { json: {
  _type: 'recap',
  scanned: pages.length,
  keyless: keyless,
  duplicateGroups: dupGroups,
  toArchive: losers.length,
  property: MATCH_PROPERTY,
  keepRule: KEEP_RULE
} };

return [...losers, recap];
